const scene = runtimeScene;
const g = scene.getGame().getVariables();
const im = scene.getGame().getInputManager();
const one = n => scene.getObjects(n)[0];
const setTxt = (n, s) => { const o = one(n); if (o) o.setString(s); };
// 讓選擇圈跟著目前英雄
const ring = one("SelRing");
if (ring) {
  const target = g.get("g_pick").getAsString() === "m" ? one("BtnHeroM") : one("BtnHeroU");
  if (target) { ring.setX(target.getX()-15); ring.setY(target.getY()-15); }
}
for (const id of im.getStartedTouchIdentifiers()) {
  const x = im.getTouchX(id), y = im.getTouchY(id);
  const hit = n => { const o = one(n); return o && o.insideObject(x, y); };
  if (hit("BtnHeroU")) g.get("g_pick").setString("u");
  else if (hit("BtnHeroM")) g.get("g_pick").setString("m");
  else if (hit("BtnTime")) {
    const cyc = {30: 45, 45: 60, 60: 30};
    const t = cyc[g.get("g_time").getAsNumber()] || 30;
    g.get("g_time").setNumber(t);
    setTxt("TxtTime", "時間：" + t + " 秒");
  } else if (hit("BtnSolo")) gdjs.evtTools.runtimeScene.replaceScene(scene, "Solo", true);
  else if (hit("BtnDuo")) gdjs.evtTools.runtimeScene.replaceScene(scene, "Duo", true);
}

const scene = runtimeScene;
const vars = scene.getVariables();
const g = scene.getGame().getVariables();
const one = n => scene.getObjects(n)[0];
const pick = g.get("g_pick").getAsString() === "m" ? "m" : "u";
if (vars.get("Phase").getAsString() === "init") {
  vars.get("Phase").setString("play");
  for (const n of ["Avatar", "SkillBtn", "SkillFx", "EnergyBar"]) {
    const o = one(n); if (o) o.setAnimationName(pick);
  }
  const sc = one("ScoreTxt");
  if (sc && pick === "m") sc.setColor("244;114;182");
  const fx = one("SkillFx"); if (fx) fx.hide(true);
  const lb = one("SkillLabel"); if (lb) lb.hide(true);
  const eb = one("EnergyBar"); if (eb) eb.setWidth(0);
}
if (vars.get("Phase").getAsString() !== "play") return;
const dt = scene.getElapsedTime() / 1000;
const skillActive = vars.get("SkillLeft").getAsNumber() > 0;
let speedFactor = 1.0, gravityOn = false;
if (skillActive) {
  vars.get("SkillLeft").setNumber(Math.max(0, vars.get("SkillLeft").getAsNumber() - dt));
  if (pick === "u") speedFactor = 0.5; else gravityOn = true;
  if (vars.get("SkillLeft").getAsNumber() <= 0) {
    const fx = one("SkillFx"); if (fx) fx.hide(true);
    const lb = one("SkillLabel"); if (lb) lb.hide(true);
  }
}
// 生成
const interval = skillActive ? 0.3 : 0.6;
vars.get("SpawnAcc").setNumber(vars.get("SpawnAcc").getAsNumber() + dt);
while (vars.get("SpawnAcc").getAsNumber() >= interval) {
  vars.get("SpawnAcc").setNumber(vars.get("SpawnAcc").getAsNumber() - interval);
  const it = scene.createObject("Item");
  if (it) {
    it.setAnimationName(pick);
    it.setWidth(88); it.setHeight(88);
    it.setX(10 + Math.random() * 1180);
    it.setY(-88);
    it.setZOrder(5);
    it.getVariables().get("vy").setNumber(200 + Math.random() * 250);
  }
}
// 移動 / 重力吸取
const fx = one("SkillFx");
const fcx = fx ? fx.getX() + fx.getWidth()/2 : 640;
const fcy = fx ? fx.getY() + fx.getHeight()/2 : 340;
for (const it of [...scene.getObjects("Item")]) {
  if (gravityOn) {
    const cx = it.getX() + 44, cy = it.getY() + 44;
    const nx = cx + (fcx - cx) * 0.15, ny = cy + (fcy - cy) * 0.15;
    it.setX(nx - 44); it.setY(ny - 44);
    if (Math.hypot(fcx - nx, fcy - ny) < 40) {
      vars.get("Score").setNumber(vars.get("Score").getAsNumber() + 1);
      gdjs.evtTools.sound.playSound(scene, "hit.mp3", false, 100, 1);
      it.deleteFromScene(scene);
    }
  } else {
    it.setY(it.getY() + it.getVariables().get("vy").getAsNumber() * speedFactor * dt);
    if (it.getY() > 720) it.deleteFromScene(scene);
  }
}
// 點擊
const im = scene.getGame().getInputManager();
for (const id of im.getStartedTouchIdentifiers()) {
  const x = im.getTouchX(id), y = im.getTouchY(id);
  const sb = one("SkillBtn");
  if (sb && sb.insideObject(x, y)) {
    if (vars.get("Energy").getAsNumber() >= 8 && !skillActive) {
      vars.get("Energy").setNumber(0);
      vars.get("SkillLeft").setNumber(pick === "u" ? 5 : 3.5);
      if (fx) { fx.hide(false); fx.setAngle(0); }
      const lb = one("SkillLabel"); if (lb) lb.hide(false);
    }
    continue;
  }
  let best = null;
  for (const it of scene.getObjects("Item")) {
    const cx = it.getX() + 44, cy = it.getY() + 44;
    if (Math.abs(x - cx) < 68 && Math.abs(y - cy) < 68) { best = it; break; }
  }
  if (best) {
    vars.get("Score").setNumber(vars.get("Score").getAsNumber() + 1);
    vars.get("Energy").setNumber(Math.min(8, vars.get("Energy").getAsNumber() + 1));
    gdjs.evtTools.sound.playSound(scene, "hit.mp3", false, 100, 1);
    best.deleteFromScene(scene);
  }
}
// HUD
const eb = one("EnergyBar");
if (eb) eb.setWidth(312 * vars.get("Energy").getAsNumber() / 8);
const sb2 = one("SkillBtn");
if (sb2) sb2.setOpacity(vars.get("Energy").getAsNumber() >= 8 ? 255 : 80);
if (fx && !fx.isHidden()) fx.setAngle(fx.getAngle() + 40 * dt);
const st = one("ScoreTxt");
if (st) st.setString(String(vars.get("Score").getAsNumber()));

const scene = runtimeScene;
const vars = scene.getVariables();
const one = n => scene.getObjects(n)[0];
if (vars.get("Phase").getAsString() === "init") {
  vars.get("Phase").setString("play");
  for (const n of ["Block1Fx", "Block2Fx"]) { const o = one(n); if (o) o.hide(true); }
}
if (vars.get("Phase").getAsString() === "end") {
  if (vars.get("EndDone").getAsNumber() === 0) {
    vars.get("EndDone").setNumber(1);
    const s1 = vars.get("Score1").getAsNumber(), s2 = vars.get("Score2").getAsNumber();
    const rt = one("ResultTitle");
    if (rt) rt.setString(s1 > s2 ? "ULTRAMAN WINS!" : s2 > s1 ? "MELODY WINS!" : "HEROIC TIE!");
    const rs = one("ResultScore");
    if (rs) rs.setString("U " + s1 + " : " + s2 + " M");
  }
  return;
}
const dt = scene.getElapsedTime() / 1000;
// 技能遮蔽倒數
for (const [bv, bn] of [["Block1", "Block1Fx"], ["Block2", "Block2Fx"]]) {
  const t = vars.get(bv).getAsNumber();
  if (t > 0) {
    vars.get(bv).setNumber(Math.max(0, t - dt));
    if (vars.get(bv).getAsNumber() <= 0) { const o = one(bn); if (o) o.hide(true); }
  }
}
// 生成（兩邊各一，每 0.7 秒）
vars.get("SpawnAcc").setNumber(vars.get("SpawnAcc").getAsNumber() + dt);
while (vars.get("SpawnAcc").getAsNumber() >= 0.7) {
  vars.get("SpawnAcc").setNumber(vars.get("SpawnAcc").getAsNumber() - 0.7);
  for (const side of [1, 2]) {
    const it = scene.createObject("Item");
    if (!it) continue;
    it.setAnimationName(side === 1 ? "u" : "m");
    it.setWidth(77); it.setHeight(77);
    it.setAngle(side === 1 ? 90 : 270);
    it.setY(20 + Math.random() * 620);
    it.setX(side === 1 ? 610 - 77 : 645);
    it.setZOrder(5);
    it.getVariables().get("vx").setNumber(180 + Math.random() * 220);
    it.getVariables().get("side").setNumber(side);
  }
}
// 移動：U 側往左、M 側往右
for (const it of [...scene.getObjects("Item")]) {
  const side = it.getVariables().get("side").getAsNumber();
  const vx = it.getVariables().get("vx").getAsNumber();
  it.setX(it.getX() + (side === 1 ? -vx : vx) * dt);
  if (it.getX() < -80 || it.getX() > 1280) it.deleteFromScene(scene);
}
// 點擊
const im = scene.getGame().getInputManager();
for (const id of im.getStartedTouchIdentifiers()) {
  const x = im.getTouchX(id), y = im.getTouchY(id);
  const side = x < 640 ? 1 : 2;
  const sb = one(side === 1 ? "SkillBtn1" : "SkillBtn2");
  if (sb && sb.insideObject(x, y)) {
    const ev_ = "Energy" + side;
    if (vars.get(ev_).getAsNumber() >= 8) {
      vars.get(ev_).setNumber(0);
      // 遮住對手半場 3 秒
      const targetBlock = side === 1 ? "Block2" : "Block1";
      vars.get(targetBlock).setNumber(3);
      const o = one(targetBlock + "Fx"); if (o) o.hide(false);
    }
    continue;
  }
  let best = null;
  for (const it of scene.getObjects("Item")) {
    if (it.getVariables().get("side").getAsNumber() !== side) continue;
    const cx = it.getX() + 38, cy = it.getY() + 38;
    if (Math.abs(x - cx) < 60 && Math.abs(y - cy) < 60) { best = it; break; }
  }
  if (best) {
    const sv = "Score" + side, ev_ = "Energy" + side;
    vars.get(sv).setNumber(vars.get(sv).getAsNumber() + 1);
    vars.get(ev_).setNumber(Math.min(8, vars.get(ev_).getAsNumber() + 1));
    gdjs.evtTools.sound.playSound(scene, "hit.mp3", false, 100, 1);
    best.deleteFromScene(scene);
  }
}
// HUD
const s1t = one("Score1Txt"); if (s1t) s1t.setString("U: " + vars.get("Score1").getAsNumber());
const s2t = one("Score2Txt"); if (s2t) s2t.setString("M: " + vars.get("Score2").getAsNumber());
const e1t = one("Energy1Txt"); if (e1t) e1t.setString("⚡ " + vars.get("Energy1").getAsNumber() + "/8");
const e2t = one("Energy2Txt"); if (e2t) e2t.setString("⚡ " + vars.get("Energy2").getAsNumber() + "/8");
const b1 = one("SkillBtn1"); if (b1) b1.setOpacity(vars.get("Energy1").getAsNumber() >= 8 ? 255 : 80);
const b2 = one("SkillBtn2"); if (b2) b2.setOpacity(vars.get("Energy2").getAsNumber() >= 8 ? 255 : 80);
